 36	import { TFunction, Trans } from 'react-i18next';
 37	import {
 38	  Modal,
 39	  Button,
 40	  ModalVariant,
 41	  FlexItem,
 42	  Flex,
 43	  Alert,
 44	  Radio,
 45	  FormGroup,
 46	  LevelItem,
 47	  Level,
 48	  AlertVariant,
 49	  ButtonVariant,
 50	  TextArea,
 51	  Title,
 52	} from '@patternfly/react-core';
 53	import { CopyIcon } from '@patternfly/react-icons';
 54	import './onboarding-modal.scss';
 55	
 56	const unlimitedQuota: StorageQuota = {
 57	  value: 0,
 58	  unit: null,
 59	};
 60	const defaultCustomQuota: StorageQuota = {
 61	  value: 1,
 62	  unit: QuotaSize.Gi,
 63	};
 64	
 65	const getTimestamp = () =>
 66	  new Intl.DateTimeFormat(getLastLanguage() || undefined, {
 67	    month: '2-digit',
 68	    day: '2-digit',
 69	    hour: '2-digit',
 70	    minute: '2-digit',
 71	    second: '2-digit',
 72	    year: 'numeric',
 73	    timeZone: 'UTC',
 74	    timeZoneName: 'short',
 75	    hour12: false,
 76	  }).format(new Date());
 77	
 78	type ClientOnBoardingModalProps = ModalComponent<{
 79	  extraProps: {
 80	    resource: StorageConsumerKind;
 81	  };
 82	  isOpen: boolean;
 83	}>;
 84	
 85	const pollUntilAvailable = async (
 86	  secretName: string,
 87	  namespace: string,
 88	  t: TFunction,
 89	  count = 0
 90	): Promise<SecretKind> => {
 91	  if (count >= 3) {
 92	    throw new Error(t('Secret not found'));
 93	  }
 94	  try {
 95	    const secret = await k8sGet({
 96	      model: SecretModel,
 97	      name: secretName,
 98	      ns: namespace,
 99	    });
100	    if (secret) {
101	      return secret;
102	    }
103	    return new Promise((resolve) => {
104	      setTimeout(() => {
105	        resolve(pollUntilAvailable(secretName, namespace, t));
106	      }, 5000);
107	    });
108	  } catch {
109	    return new Promise((resolve) => {
110	      setTimeout(() => {
111	        resolve(pollUntilAvailable(secretName, namespace, t));
112	      }, 5000);
113	    });
114	  }
115	};
