117	export const ClientOnBoardingModal: ClientOnBoardingModalProps = ({
118	  isOpen,
119	  closeModal,
120	  extraProps: { resource: storageConsumer },
121	}) => {
122	  const { t } = useCustomTranslation();
123	  const [token, setToken] = React.useState('');
124	  const [tokenGenerationTimestamp, setTokenGenerationTimestamp] =
125	    React.useState('');
126	  const [inProgress, setInProgress] = React.useState(false);
127	  const [error, setError] = React.useState<string>(null);
128	  const secretName = storageConsumer.status?.onboardingTicketSecret?.name;
129	  const namespace = getNamespace(storageConsumer);
130	
131	  const [secretResource, ,] = useK8sGet(
132	    SecretModel as K8sKind,
133	    secretName,
134	    namespace
135	  );
136	
137	  const generateToken = () => {
138	    setInProgress(true);
139	    k8sDelete({
140	      model: SecretModel,
141	      resource: secretResource,
142	    })
143	      .then(() => {
144	        pollUntilAvailable(secretName, namespace, t)
145	          .then((secret) => {
146	            setToken(Base64.decode(secret.data['onboarding-token']));
147	            setTokenGenerationTimestamp(getTimestamp());
148	            setInProgress(false);
149	          })
150	          .catch((err) => {
151	            setInProgress(false);
152	            setError(err);
153	          });
154	      })
155	      .catch((err) => {
156	        setInProgress(false);
157	        setError(err);
158	      });
159	  };
160	
161	  const quotaInGib = storageConsumer.spec?.storageQuotaInGiB;
162	  const storageQuota = quotaInGib
163	    ? humanizeBinaryBytesWithoutB(quotaInGib, 'Gi').string
164	    : t('Unlimited');
165	
166	  return (
167	    <Modal isOpen={isOpen} onClose={closeModal} variant={ModalVariant.medium}>
168	      <ModalTitle>{t('Generate token')}</ModalTitle>
169	      {token ? (
170	        <ModalBody>
171	          <TokenViewBody
172	            token={token}
173	            tokenGenerationTimestamp={tokenGenerationTimestamp}
174	          />
175	        </ModalBody>
176	      ) : (
177	        <>
178	          <ModalBody>
179	            <p className="odf-onboarding-modal__title-desc">
180	              {t(
181	                `An onboarding token to authenticate and authorize an OpenShift cluster, granting access to the Data Foundation deployment, thus establishing a secure connection.`
182	              )}
183	            </p>
184	            <Flex direction={{ default: 'column' }}>
185	              <FlexItem>
186	                <span className="odf-onboarding-modal__quota-desc">
187	                  <Title headingLevel="h5" size="md">
188	                    {t('StorageConsumer')}:{' '}
189	                  </Title>
190	                  {storageConsumer.metadata.name}
191	                </span>
192	              </FlexItem>
193	              <FlexItem>
194	                <span className="odf-onboarding-modal__quota-desc">
195	                  <Title headingLevel="h5" size="md">
196	                    {t('Storage quota')}:{' '}
197	                  </Title>
198	                  {storageQuota}
199	                </span>
200	              </FlexItem>
201	            </Flex>
202	            {error && (
203	              <Alert
204	                variant={AlertVariant.danger}
205	                isInline
206	                title={t('Can not generate an onboarding token at the moment')}
207	              >
208	                <Trans>
209	                  The token generation service is currently unavailable. Contact
210	                  our{' '}
211	                  <ExternalLink href="https://access.redhat.com/support/">
212	                    customer support
213	                  </ExternalLink>{' '}
214	                  for further help.
215	                </Trans>
216	              </Alert>
217	            )}
218	          </ModalBody>
219	          <ModalFooter inProgress={inProgress}>
220	            <Flex direction={{ default: 'row' }}>
221	              <FlexItem>
222	                <Button
223	                  key="cancel"
224	                  variant={ButtonVariant.secondary}
225	                  onClick={closeModal}
226	                  data-test-id="modal-cancel-action"
227	                >
228	                  {t('Cancel')}
229	                </Button>
230	              </FlexItem>
231	              <FlexItem>
232	                <Button
233	                  key="save"
234	                  data-test="modal-submit-action"
235	                  data-test-id="confirm-action"
236	                  variant={ButtonVariant.primary}
237	                  onClick={() => generateToken()}
238	                  isDisabled={inProgress}
239	                  isLoading={inProgress}
240	                >
241	                  {inProgress ? t('Generating token') : t('Generate token')}
242	                </Button>
243	              </FlexItem>
244	            </Flex>
245	          </ModalFooter>
246	        </>
247	      )}
248	    </Modal>
249	  );
250	};
