252	type StorageQuotaBodyProps = {
253	  quota: StorageQuota;
254	  setQuota: React.Dispatch<React.SetStateAction<StorageQuota>>;
255	  initialQuota?: StorageQuota;
256	  capacityInfo?: React.ReactNode;
257	};
258	
259	export const StorageQuotaBody: React.FC<StorageQuotaBodyProps> = ({
260	  quota,
261	  setQuota,
262	  initialQuota,
263	  capacityInfo,
264	}) => {
265	  const { t } = useCustomTranslation();
266	
267	  const onCustomQuotaChange = (customQuota: StorageQuota) => {
268	    setQuota({ ...customQuota });
269	  };
270	
271	  const unlimitedQuotaTypeText = t('Unlimited');
272	  const customQuotaTypeText = t('Custom');
273	
274	  return (
275	    <>
276	      <FormGroup
277	        label={`${t('Storage quota:')} ${
278	          isUnlimitedQuota(quota) ? unlimitedQuotaTypeText : customQuotaTypeText
279	        }`}
280	        labelInfo={capacityInfo}
281	        className="pf-v6-u-font-size-md odf-onboarding-modal__quota-desc"
282	      >
283	        <Radio
284	          label={unlimitedQuotaTypeText}
285	          value="unlimited"
286	          id="storage-quota-unlimited"
287	          name="storage-quota"
288	          description={<UnlimitedRadioDescription quota={quota} />}
289	          isChecked={isUnlimitedQuota(quota)}
290	          onChange={() => {
291	            setQuota({ ...unlimitedQuota });
292	          }}
293	        />
294	        <Radio
295	          label={customQuotaTypeText}
296	          value="custom"
297	          id="storage-quota-custom"
298	          name="storage-quota"
299	          description={t(
300	            'Limit the amount of storage that a client cluster can consume.'
301	          )}
302	          className="pf-v6-u-mt-lg"
303	          isChecked={!isUnlimitedQuota(quota)}
304	          isDisabled={initialQuota && isUnlimitedQuota(initialQuota)}
305	          onChange={() => {
306	            setQuota({ ...(initialQuota || defaultCustomQuota) });
307	          }}
308	        />
309	      </FormGroup>
310	      {!isUnlimitedQuota(quota) && (
311	        <div className="pf-v6-u-ml-lg pf-v6-u-mt-md">
312	          <span className="pf-v6-u-font-weight-bold">
313	            {t('Allocate quota')}
314	          </span>
315	          <RequestSizeInput
316	            name={t('Allocate quota')}
317	            onChange={onCustomQuotaChange}
318	            dropdownUnits={QuotaSizeUnitOptions}
319	            defaultRequestSizeUnit={quota.unit}
320	            defaultRequestSizeValue={String(quota.value)}
321	            minValue={1}
322	          >
323	            {!isValidQuota(quota, initialQuota) && (
324	              <Alert
325	                className="odf-onboarding-modal__invalid-quota"
326	                variant={AlertVariant.danger}
327	                isInline
328	                title={t(
329	                  'Storage quota cannot be decreased. Assign a quota higher than your current allocation.'
330	                )}
331	              ></Alert>
332	            )}
333	          </RequestSizeInput>
334	        </div>
335	      )}
336	    </>
337	  );
338	};
339	
340	type UnlimitedRadioDescriptionProps = {
341	  quota: StorageQuota;
342	};
343	
344	const UnlimitedRadioDescription: React.FC<UnlimitedRadioDescriptionProps> = ({
345	  quota,
346	}) => {
347	  const { t } = useCustomTranslation();
348	  return (
349	    <>
350	      <p>
351	        {t('No specific limit on storage that a client cluster can consume.')}
352	      </p>
353	      {isUnlimitedQuota(quota) && (
354	        <Alert
355	          variant={AlertVariant.info}
356	          isInline
357	          title={t(
358	            'Changing the storage quota from unlimited to custom is not supported after the client cluster is onboarded.'
359	          )}
360	        ></Alert>
361	      )}
362	    </>
363	  );
364	};
365	
366	type TokenViewBodyProps = {
367	  token: string;
368	  tokenGenerationTimestamp: string;
369	};
370	
371	const TokenViewBody: React.FC<TokenViewBodyProps> = ({
372	  token,
373	  tokenGenerationTimestamp,
374	}) => {
375	  const { t } = useCustomTranslation();
376	
377	  const onCopyToClipboard = () => {
378	    navigator.clipboard.writeText(token);
379	  };
380	
381	  return (
382	    <Flex direction={{ default: 'column' }}>
383	      <FlexItem>
384	        <Level>
385	          <LevelItem className="pf-v6-u-font-weight-bold">
386	            {t('Onboarding token')}
387	            <FieldLevelHelp position="right">
388	              {onboardingTokenTooltip(t)}
389	            </FieldLevelHelp>
390	          </LevelItem>
391	          <LevelItem>
392	            <span className="pf-v6-u-font-size-sm pf-v5-u-color-200">
393	              {t('Generated on')}: {tokenGenerationTimestamp}
394	            </span>
395	            <span className="pf-v6-u-ml-sm odf-onboarding-modal__timestamp-icon">
396	              <GreenCheckCircleIcon />
397	            </span>
398	          </LevelItem>
399	        </Level>
400	      </FlexItem>
401	      <FlexItem grow={{ default: 'grow' }}>
402	        <TextArea
403	          value={token}
404	          className="odf-onboarding-modal__text-area"
405	          aria-label={t('Onboarding token')}
406	          readOnlyVariant="default"
407	          resizeOrientation="vertical"
408	        />
409	      </FlexItem>
410	      <FlexItem className="pf-v6-u-mb-lg">
411	        <Trans t={t} ns="plugin__odf-console">
412	          On an OpenShift cluster, deploy the Data Foundation client operator
413	          using the generated token.
414	        </Trans>
415	      </FlexItem>
416	      <FlexItem>
417	        <Button
418	          type="button"
419	          onClick={onCopyToClipboard}
420	          variant={ButtonVariant.primary}
421	          className="odf-onboarding-modal__clipboard"
422	        >
423	          <CopyIcon className="pf-v6-u-ml-md pf-v6-u-mr-sm" />
424	          {t('Copy to clipboard')}
425	        </Button>
426	      </FlexItem>
427	      <FlexItem>
428	        <StatusIconAndText
429	          title={t(
430	            'This token is for one-time use only and is valid for 48 hours.'
431	          )}
432	          icon={<BlueInfoCircleIcon />}
433	          className="text-muted odf-onboarding-modal__info-icon"
434	        />
435	      </FlexItem>
436	    </Flex>
437	  );
438	};

